import { Col, Divider, Row, Select, Tooltip } from "antd"
import { useCallback, useEffect, useState } from "react"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputDebounceCustom from "src/components/Input/InputDebounceCustom"
import Delete from "src/components/Modal/Delete"
import ButtonCustom from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import TableCustom from "src/components/Table/CustomTable"
import { hideOnSinglePage } from "src/constants/constants"
import { renderButtonCircle } from "src/lib/utils"
import RoleService from "src/services/RoleService"
import ModalRoleGroupForm from "./ModalRoleGroupForm"
import { RoleStyled } from "./styled"

const Role = () => {
  const [loading, setLoading] = useState(false)
  const [isEditRole, setIsEditRole] = useState(false)
  const [dataSource, setDataSource] = useState([])
  const [pagination, setPagination] = useState({
    PageSize: 50,
    CurrentPage: 1,
  })
  const [total, setTotal] = useState(0)
  const [openModalEdit, setOpenModalEdit] = useState(false)
  const [dataInfo, setDataInfo] = useState()
  const [openDeleteModal, setOpenDeleteModal] = useState(false)
  const [infoDelete, setInfoDelete] = useState()
  const [TextSearch, setTextSearch] = useState("")
  const [status, setStatus] = useState(1)

  const getListRole = useCallback(
    (paginationProps = pagination) => {
      setLoading(true)
      RoleService.getListRole({
        IsActive: !!status,
        TextSearch: TextSearch,
        ...paginationProps,
      })
        .then(res => {
          if (res?.isError) return
          setDataSource(res?.Object?.data)
          setTotal(res?.Object?.total)
        })
        .finally(() => setLoading(false))
    },
    [status, TextSearch, pagination],
  )

  const deleteRole = () => {
    RoleService.deleteRole({ roleId: infoDelete.RoleID }).then(res => {
      if (res?.isError) return
      getListRole()
      Notice({
        isSuccess: true,
        msg: "Xóa nhóm quyền thành công",
      })
    })
  }

  // Sử dụng useEffect đúng cách
  useEffect(() => {
    getListRole()
  }, [status]) // Chỉ trigger khi status thay đổi

  // Handle debounced search
  const handleDebouncedSearch = useCallback(
    searchValue => {
      setTextSearch(searchValue)
      const newPagination = { ...pagination, CurrentPage: 1 }
      setPagination(newPagination)

      // Gọi API với giá trị search mới
      setLoading(true)
      RoleService.getListRole({
        IsActive: !!status,
        TextSearch: searchValue,
        ...newPagination,
      })
        .then(res => {
          if (res?.isError) return
          setDataSource(res?.Object?.data)
          setTotal(res?.Object?.total)
        })
        .finally(() => setLoading(false))
    },
    [status, pagination],
  )

  const columns = [
    {
      title: "STT",
      dataIndex: "id",
      key: "id",
      width: 60,
      render: (val, record, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1)}
        </div>
      ),
      align: "center",
    },
    {
      title: "Tên nhóm quyền",
      dataIndex: "RoleName",
      key: "RoleName",
      width: 300,
    },
    {
      title: "Quyền nguyên tố",
      dataIndex: "ListCategory",
      key: "ListCategory",
      render: (val, record) => (
        <>
          <div className="fw-600">{record.RoleType}:</div>
          <ul>
            {val?.map(i => (
              <Tooltip
                mouseEnterDelay={0.5}
                title={`${i.DescriptionCategory}: ${i.ListFunction?.map(
                  data => data.DescriptionFunction,
                ).join(", ")}`}
                key={`tip${i.CategoryID}`}
              >
                <li
                  key={`${i?.categoryId}${i?.DescriptionCategory}`}
                  className="text-ellipsis text-ellipsis-1"
                >
                  {`• ${i.DescriptionCategory}: ${i.ListFunction?.map(
                    data => data.DescriptionFunction,
                  ).join(", ")}`}
                </li>
              </Tooltip>
            ))}
          </ul>
        </>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "IsDelete",
      key: "IsDelete",
      align: "center",
      width: 200,
      render: (val, record) => (
        <div>
          <div>
            {val ? (
              <div className="fw-600" style={{ color: "#ff4d4f" }}>
                Không hoạt động
              </div>
            ) : (
              <div className="fw-600" style={{ color: "#0D99FF" }}>
                Đang hoạt động
              </div>
            )}
          </div>
          <FloatActionWrapper size="small" className="float-action__wrapper">
            {renderButtonCircle(
              "Chỉnh sửa",
              "edit",
              () => {
                setIsEditRole(true)
                setDataInfo(record)
                setOpenModalEdit(true)
              },
              true,
            )}
            {renderButtonCircle(
              "Xoá",
              "bin",
              () => {
                setOpenDeleteModal(true)
                setInfoDelete(record)
              },
              true,
            )}
          </FloatActionWrapper>
        </div>
      ),
    },
  ]

  return (
    <RoleStyled>
      <Row className="box-action" gutter={16}>
        <Col span={18}>
          <InputDebounceCustom
            type="search"
            allowClear
            label="Nhập tên nhóm quyền"
            value={TextSearch}
            onChange={e => setTextSearch(e?.target?.value)}
            onDebouncedChange={handleDebouncedSearch}
            debounceDelay={300}
          />
        </Col>
        <Col span={6}>
          <SelectCustom
            style={{ width: "100%" }}
            onChange={status => setStatus(status)}
            value={status}
            maxTagCount="responsive"
            label="Trạng thái"
          >
            <Select.Option value={1} key={1}>
              Đang hoạt động
            </Select.Option>
            <Select.Option value={0} key={0}>
              Không hoạt động
            </Select.Option>
          </SelectCustom>
        </Col>
      </Row>

      <Divider />
      <div className="title-type-1 d-flex justify-content-space-between align-items-center">
        <span className="fs-24">Phân quyền</span>
        <ButtonCustom
          iconName="add"
          className="btn-hover-shadow"
          onClick={() => {
            setIsEditRole(false)
            setDataInfo(undefined)
            setOpenModalEdit(true)
          }}
        >
          Thêm nhóm quyền
        </ButtonCustom>
      </div>

      <TableCustom
        isPrimary
        columns={columns}
        dataSource={dataSource}
        loading={loading}
        sticky={{ offsetHeader: 52 }}
        scroll={{ x: "800px" }}
        pagination={{
          hideOnSinglePage: total <= hideOnSinglePage,
          current: pagination.CurrentPage,
          pageSize: pagination.PageSize,
          responsive: true,
          total,
          locale: { items_per_page: "" },
          showSizeChanger: total > 10,
          onChange: (page, PageSize) => {
            const newPagination = {
              ...pagination,
              CurrentPage: page,
              PageSize,
            }
            setPagination(newPagination)
            getListRole(newPagination)
          },
        }}
        showPagination
        rowKey={record => `${record?.RoleID}${record?.LastUpdate}`}
        footerLeft={<div className="d-flex mt-20" />}
        widthScroll={1200}
        textEmpty="Không có Nhóm quyền nào!"
      />

      {openDeleteModal && (
        <Delete
          isOpen={!!openDeleteModal}
          content={{
            title: (
              <div className="fw-600 text-center" style={{ fontSize: 16 }}>
                Bạn có chắc chắn muốn xóa nhóm quyền "
                <b>{infoDelete?.RoleName}</b>" không?
              </div>
            ),
          }}
          onOk={() => {
            deleteRole()
            setOpenDeleteModal(false)
          }}
          onCancel={() => setOpenDeleteModal(false)}
        />
      )}

      {openModalEdit && (
        <ModalRoleGroupForm
          isEditRole={isEditRole}
          visible={openModalEdit}
          dataInfo={dataInfo}
          onOk={() => {
            getListRole()
            setDataInfo(undefined)
            setIsEditRole(false)
            setOpenModalEdit(false)
          }}
          onCancel={() => {
            setDataInfo(undefined)
            setIsEditRole(false)
            setOpenModalEdit(false)
          }}
        />
      )}
    </RoleStyled>
  )
}

export default Role
